// ─── API 调用 ────────────────────────────────────────────────────────────────

interface CallOptions {
  model?: string
  systemPrompt?: string
  temperature?: number
  maxTokens?: number
  topP?: number
  presencePenalty?: number
  frequencyPenalty?: number
}

async function callAI(
  prompt: string,
  options: CallOptions = {}
): Promise<{ success: boolean; content?: string; reasoning?: string; error?: string }> {
  const { model = 'deepseek', systemPrompt, temperature = 0.7, maxTokens = 2000 } = options

  const fallbackKey = model.startsWith('doubao')
    ? process.env.DOUBAO_API_KEY
    : process.env.DEEPSEEK_API_KEY
